from flask import Flask, request, jsonify
from flask_jwt_extended import JWTManager

app = Flask(__name__)
app.config["JWT_SECRET_KEY"] = "your-secret-key"
jwt = JWTManager(app)

@app.route("/login", methods=["POST"])
def login():
    # Authenticate user and generate token
    user = {"username": "user123", "password": "password123"}
    if request.json["username"] == user["username"] and request.json["password"] == user["password"]:
        access_token = jwt.encode({"user_id": 1})
        return jsonify({"access_token": access_token})
    else:
        return jsonify({"error": "Invalid credentials"}), 401

@app.route("/protected", methods=["GET"])
def protected():
    # Verify token and allow request if valid, otherwise return error
    try:
        data = jwt.decode_token(request.headers["Authorization"].split(" ")[1])
        user_id = data["user_id"]
        return jsonify({"message": f"Hello {user_id}!"})
    except jwt.InvalidTokenError:
        return jsonify({"error": "Invalid or expired token"}), 401

if __name__ == "__main__":
    app.run()